// bannerKind defaults the variant to "warning" so callers passing an empty
// Kind still get a sane colour modifier in the class list.
func bannerKind(k string) string {
	if k == "" {
		return "warning"
	}
	return k
}

type galleryItem struct {
	URL string `json:"u"`
	W   int64  `json:"w"`
	H   int64  `json:"h"`
}

func galleryJSON(g []reddit.GalleryMedia) string {
	items := make([]galleryItem, len(g))
	for i, m := range g {
		items[i] = galleryItem{URL: m.URL, W: m.Width, H: m.Height}
	}
	b, _ := json.Marshal(items)
	return string(b)
}

